const input = $input.first().json;
const action = input.action || 'list_knowledge';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

async function getCred(key) {
  const res = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.openwebui-knowledge&cred_key=eq.' + key + '&select=cred_value',
    headers: pgHeaders
  });
  return (res && res.length > 0) ? res[0].cred_value : null;
}

const baseUrl = await getCred('openwebui_url');
const apiKey = await getCred('openwebui_api_key');

if (!baseUrl || !apiKey) {
  return [{ json: { error: 'OpenWebUI credentials not configured. Use add_credential to set openwebui_url and openwebui_api_key.' } }];
}

const apiBase = baseUrl.replace(/\/$/, '') + '/api/v1';
const authHeaders = {
  'Authorization': 'Bearer ' + apiKey,
  'Content-Type': 'application/json'
};

async function apiRequest(method, path, body) {
  const opts = {
    method,
    url: apiBase + path,
    headers: { ...authHeaders },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    json: false
  };
  if (body) opts.body = JSON.stringify(body);
  const resp = await helpers.httpRequest(opts);
  if (resp.statusCode >= 400) {
    const errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
    throw new Error('API returned ' + resp.statusCode + ': ' + errBody.substring(0, 500));
  }
  return typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
}

function formatSize(bytes) {
  if (!bytes || bytes === 0) return '0 B';
  const n = Number(bytes);
  if (n < 1024) return n + ' B';
  if (n < 1024 * 1024) return (n / 1024).toFixed(1) + ' KB';
  if (n < 1024 * 1024 * 1024) return (n / (1024 * 1024)).toFixed(1) + ' MB';
  return (n / (1024 * 1024 * 1024)).toFixed(1) + ' GB';
}

// === list_knowledge ===
if (action === 'list_knowledge') {
  try {
    const raw = await apiRequest('GET', '/knowledge/');
    const collections = Array.isArray(raw) ? raw : (raw && raw.items ? raw.items : (raw && raw.data ? raw.data : []));
    if (collections.length === 0) {
      return [{ json: { result: 'No knowledge collections found.' } }];
    }
    let result = 'Knowledge Collections (' + collections.length + '):\n\n';
    for (const c of collections) {
      const fileCount = (c.files || c.data?.file_ids || []).length;
      result += '- ' + (c.name || 'Unnamed') + '\n';
      result += '  ID: ' + c.id + '\n';
      if (c.description) result += '  Description: ' + c.description + '\n';
      result += '  Files: ' + fileCount + '\n\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list knowledge collections: ' + err.message } }];
  }

// === create_knowledge ===
} else if (action === 'create_knowledge') {
  const name = input.name;
  if (!name) return [{ json: { error: 'Parameter "name" is required.' } }];
  try {
    const body = { name };
    if (input.description) body.description = input.description;
    const created = await apiRequest('POST', '/knowledge/create', body);
    return [{ json: { result: 'Knowledge collection created: ' + created.name + ' (ID: ' + created.id + ')' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create knowledge collection: ' + err.message } }];
  }

// === get_knowledge ===
} else if (action === 'get_knowledge') {
  const id = input.knowledge_id;
  if (!id) return [{ json: { error: 'Parameter "knowledge_id" is required.' } }];
  try {
    const k = await apiRequest('GET', '/knowledge/' + encodeURIComponent(id));
    let result = 'Knowledge Collection: ' + (k.name || 'Unnamed') + '\n';
    result += 'ID: ' + k.id + '\n';
    if (k.description) result += 'Description: ' + k.description + '\n';
    // GET /knowledge/{id} returns files:null — fetch files separately and filter by collection_name
    let files = [];
    if (Array.isArray(k.files) && k.files.length > 0) {
      files = k.files;
    } else {
      try {
        const allFiles = await apiRequest('GET', '/files/');
        const fileList = Array.isArray(allFiles) ? allFiles : (allFiles && allFiles.items ? allFiles.items : []);
        files = fileList.filter(f => f.meta && f.meta.collection_name === id);
      } catch(e) { /* ignore — just show no files */ }
    }
    if (files.length === 0) {
      result += 'Files: none\n';
    } else {
      result += 'Files (' + files.length + '):\n';
      for (const f of files) {
        const size = f.meta?.size ? formatSize(f.meta.size) : 'unknown size';
        result += '  - ' + (f.filename || f.meta?.name || 'unnamed') + ' (' + size + ')\n';
        result += '    File ID: ' + f.id + '\n';
      }
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get knowledge collection: ' + err.message } }];
  }

// === update_knowledge ===
} else if (action === 'update_knowledge') {
  const id = input.knowledge_id;
  if (!id) return [{ json: { error: 'Parameter "knowledge_id" is required.' } }];
  const updates = {};
  if (input.name) updates.name = input.name;
  if (input.description !== undefined && input.description !== '') updates.description = input.description;
  if (Object.keys(updates).length === 0) {
    return [{ json: { error: 'Provide at least one of: name, description.' } }];
  }
  try {
    const updated = await apiRequest('POST', '/knowledge/' + encodeURIComponent(id) + '/update', updates);
    return [{ json: { result: 'Knowledge collection updated: ' + (updated.name || id) } }];
  } catch (err) {
    return [{ json: { error: 'Failed to update knowledge collection: ' + err.message } }];
  }

// === delete_knowledge ===
} else if (action === 'delete_knowledge') {
  const id = input.knowledge_id;
  if (!id) return [{ json: { error: 'Parameter "knowledge_id" is required.' } }];
  try {
    await apiRequest('DELETE', '/knowledge/' + encodeURIComponent(id) + '/delete');
    return [{ json: { result: 'Knowledge collection deleted: ' + id } }];
  } catch (err) {
    return [{ json: { error: 'Failed to delete knowledge collection: ' + err.message } }];
  }

// === list_files ===
} else if (action === 'list_files') {
  try {
    const rawFiles = await apiRequest('GET', '/files/');
    const files = Array.isArray(rawFiles) ? rawFiles : (rawFiles && rawFiles.data ? rawFiles.data : []);
    if (files.length === 0) {
      return [{ json: { result: 'No files found.' } }];
    }
    let result = 'Files (' + files.length + '):\n\n';
    for (const f of files) {
      const size = f.meta?.size ? formatSize(f.meta.size) : 'unknown size';
      const name = f.filename || f.meta?.name || 'unnamed';
      result += '- ' + name + ' (' + size + ')\n';
      result += '  ID: ' + f.id + '\n';
      if (f.meta?.content_type) result += '  Type: ' + f.meta.content_type + '\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list files: ' + err.message } }];
  }

// === upload_file ===
} else if (action === 'upload_file') {
  const knowledgeId = input.knowledge_id;
  const url = input.url;
  const filename = input.filename;
  if (!knowledgeId || !url || !filename) {
    return [{ json: { error: 'Parameters required: knowledge_id, url, filename.' } }];
  }
  try {
    // Step 1: Download file from URL
    const dlResp = await helpers.httpRequest({
      method: 'GET',
      url: url,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
      encoding: 'arraybuffer'
    });
    if (dlResp.statusCode >= 400) {
      return [{ json: { error: 'Failed to download from URL. Status: ' + dlResp.statusCode } }];
    }
    const fileBuffer = Buffer.from(dlResp.body);

    // Step 2: Upload to OpenWebUI as multipart/form-data
    const boundary = '----n8nFormBoundary' + Date.now();
    const ct = (dlResp.headers && (dlResp.headers['content-type'] || '')) || 'application/octet-stream';
    const parts = [];
    parts.push('--' + boundary + '\r\n');
    parts.push('Content-Disposition: form-data; name="file"; filename="' + filename.replace(/"/g, '\\"') + '"\r\n');
    parts.push('Content-Type: ' + ct + '\r\n\r\n');
    const header = Buffer.from(parts.join(''), 'utf-8');
    const footer = Buffer.from('\r\n--' + boundary + '--\r\n', 'utf-8');
    const multipartBody = Buffer.concat([header, fileBuffer, footer]);

    const uploadResp = await helpers.httpRequest({
      method: 'POST',
      url: apiBase + '/files/',
      headers: {
        'Authorization': 'Bearer ' + apiKey,
        'Content-Type': 'multipart/form-data; boundary=' + boundary
      },
      body: multipartBody,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
      encoding: 'arraybuffer'
    });
    if (uploadResp.statusCode >= 400) {
      const errText = Buffer.from(uploadResp.body).toString('utf-8').substring(0, 500);
      return [{ json: { error: 'Failed to upload file to OpenWebUI. Status: ' + uploadResp.statusCode + ' Body: ' + errText } }];
    }
    const uploadData = JSON.parse(Buffer.from(uploadResp.body).toString('utf-8'));
    const fileId = uploadData.id;
    if (!fileId) {
      return [{ json: { error: 'Upload succeeded but no file ID returned. Response: ' + JSON.stringify(uploadData).substring(0, 300) } }];
    }

    // Step 3: Add file to knowledge collection
    await apiRequest('POST', '/knowledge/' + encodeURIComponent(knowledgeId) + '/file/add', { file_id: fileId });
    return [{ json: { result: 'File uploaded and added to knowledge collection.\nFilename: ' + filename + '\nFile ID: ' + fileId + '\nSize: ' + formatSize(fileBuffer.length) } }];
  } catch (err) {
    return [{ json: { error: 'Failed to upload file: ' + err.message } }];
  }

// === ingest_web_url ===
} else if (action === 'ingest_web_url') {
  const knowledgeId = input.knowledge_id;
  const url = input.url;
  if (!knowledgeId || !url) {
    return [{ json: { error: 'Parameters required: knowledge_id, url.' } }];
  }
  try {
    // Process web URL with collection_name = knowledge ID so content is indexed for this collection's RAG
    const processed = await apiRequest('POST', '/retrieval/process/web', { url, collection_name: knowledgeId });
    if (!processed.status) {
      const detail = processed.detail || JSON.stringify(processed).substring(0, 300);
      return [{ json: { error: 'Failed to process web URL: ' + detail } }];
    }
    return [{ json: { result: 'Web page ingested into knowledge collection for RAG.\nURL: ' + url + '\nCollection: ' + knowledgeId + '\nNote: Content is indexed for retrieval. It may not appear as a file in the collection list.' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to ingest web URL: ' + err.message } }];
  }

// === remove_file ===
} else if (action === 'remove_file') {
  const knowledgeId = input.knowledge_id;
  const fileId = input.file_id;
  if (!knowledgeId || !fileId) {
    return [{ json: { error: 'Parameters required: knowledge_id, file_id.' } }];
  }
  try {
    // Step 1: Remove file from knowledge collection
    await apiRequest('POST', '/knowledge/' + encodeURIComponent(knowledgeId) + '/file/remove', { file_id: fileId });
    // Step 2: Delete the file itself
    try {
      await apiRequest('DELETE', '/files/' + encodeURIComponent(fileId));
    } catch (delErr) {
      return [{ json: { result: 'File removed from knowledge collection but could not delete the file itself: ' + delErr.message } }];
    }
    return [{ json: { result: 'File removed from knowledge collection and deleted.\nFile ID: ' + fileId } }];
  } catch (err) {
    return [{ json: { error: 'Failed to remove file: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Valid actions: list_knowledge, create_knowledge, get_knowledge, update_knowledge, delete_knowledge, list_files, upload_file, ingest_web_url, remove_file.' } }];
}
